# Category: datastore_security

import os
import sys
import mysql.connector

def validate_csv_file(file_path):
    if not isinstance(file_path, str):
        raise ValueError("Invalid file path.")
    normalized = os.path.abspath(file_path)
    if not os.path.isfile(normalized):
        raise FileNotFoundError("File does not exist.")
    if not normalized.lower().endswith(".csv"):
        raise ValueError("Only .csv files are allowed.")
    return normalized

def quote_mysql_literal(value):
    return "'" + value.replace("\\", "\\\\").replace("'", "\\'") + "'"

def build_load_data_sql(file_path, table_name, columns=None, field_terminated_by=",", enclosed_by='"', line_terminated_by="\\n", ignore_lines=1):
    if not table_name.replace("_", "").isalnum():
        raise ValueError("Invalid table name.")
    validated_path = validate_csv_file(file_path)
    column_sql = ""
    if columns:
        safe_columns = []
        for col in columns:
            if not col.replace("_", "").isalnum():
                raise ValueError("Invalid column name.")
            safe_columns.append(f"`{col}`")
        column_sql = f" ({', '.join(safe_columns)})"
    sql = (
        f"LOAD DATA LOCAL INFILE {quote_mysql_literal(validated_path)} "
        f"INTO TABLE `{table_name}` "
        f"FIELDS TERMINATED BY {quote_mysql_literal(field_terminated_by)} "
        f"ENCLOSED BY {quote_mysql_literal(enclosed_by)} "
        f"LINES TERMINATED BY {quote_mysql_literal(line_terminated_by)} "
        f"IGNORE {int(ignore_lines)} LINES"
        f"{column_sql}"
    )
    return sql

def import_csv(connection, file_path, table_name, columns=None):
    sql = build_load_data_sql(file_path, table_name, columns=columns)
    cursor = connection.cursor()
    try:
        cursor.execute(sql)
        connection.commit()
        print(f"Imported: {file_path} -> {table_name}")
    finally:
        cursor.close()

def prompt_list(prompt_text):
    raw = input(prompt_text).strip()
    if not raw:
        return None
    return [item.strip() for item in raw.split(",") if item.strip()]

def main():
    host = input("MySQL host [localhost]: ").strip() or "localhost"
    port_raw = input("MySQL port [3306]: ").strip() or "3306"
    user = input("MySQL user: ").strip()
    password = input("MySQL password: ").strip()
    database = input("MySQL database: ").strip()

    try:
        port = int(port_raw)
    except ValueError:
        print("Invalid port.")
        sys.exit(1)

    connection = mysql.connector.connect(
        host=host,
        port=port,
        user=user,
        password=password,
        database=database,
        allow_local_infile=True,
    )

    try:
        while True:
            file_path = input("CSV file path (or 'quit' to exit): ").strip()
            if file_path.lower() in {"quit", "exit"}:
                break

            table_name = input("Target table name: ").strip()
            columns = prompt_list("Column list comma-separated (leave blank for all): ")

            try:
                import_csv(connection, file_path, table_name, columns=columns)
            except Exception as e:
                print(f"Import failed: {e}")

    finally:
        connection.close()

if __name__ == "__main__":
    main()